import java.util.ArrayList;
import java.util.List;

class TeamMember {
    private String name;
    private String role;
    private String yesterday;
    private String today;
    private String blocker;

    public TeamMember(String name, String role) {
        this.name = name;
        this.role = role;
    }

    // Getters and setters
    public void updateStatus(String yesterday, String today) {
        this.yesterday = yesterday;
        this.today = today;
    }

    public void setBlocker(String blocker) {
        this.blocker = blocker;
    }

    public void speak() {
        System.out.println("  " + name + " (" + role + "):");
        System.out.println("    Yesterday: " + yesterday);
        System.out.println("    Today: " + today);
        if (blocker != null && !blocker.isEmpty()) {
            System.out.println("    BLOCKER: " + blocker);
        }
    }
}

class DailyStandup {
    private String sprintName;
    private List<TeamMember> team;

    public DailyStandup(String sprintName) {
        this.sprintName = sprintName;
        this.team = new ArrayList<>();
    }

    public void addMember(TeamMember member) {
        team.add(member);
    }

    public void conductMeeting() {
        System.out.println("\n=== Daily Standup for " + sprintName + " ===");
        System.out.println("Duration: 15 minutes maximum");
        System.out.println("Questions: What did you do? What will you do? Any blockers?\n");

        for (TeamMember member : team) {
            member.speak();
        }
    }
}

public class AgileStandupDemo {
    public static void main(String[] args) {
        // Create agile team
        DailyStandup standup = new DailyStandup("Sprint 2 - Week 1");

        TeamMember dev1 = new TeamMember("Alice", "Developer");
        dev1.updateStatus("Completed login API", "Work on user dashboard");

        TeamMember dev2 = new TeamMember("Bob", "Developer");
        dev2.updateStatus("Fixed cart bug", "Start payment integration");
        dev2.setBlocker("Need API documentation from backend team");

        TeamMember tester = new TeamMember("Charlie", "QA Engineer");
        tester.updateStatus("Tested search feature", "Begin testing login flow");

        standup.addMember(dev1);
        standup.addMember(dev2);
        standup.addMember(tester);

        standup.conductMeeting();
    }
}
